  .wready_o   (sfifo_distr_not_full),
  .rvalid_o   (sfifo_distr_not_empty),
  .rdata_o    (sfifo_distr_rdata),
  .rready_i   (sfifo_distr_pop),
  .full_o     (sfifo_distr_full),
  .depth_o    (sfifo_distr_depth),
  .err_o      (sfifo_distr_int_err)
);

